<template><span class="badge" :data-status="status">{{t(`promptops.evaluations.status.${status}`)}}</span></template><script setup lang="ts">import{useI18n}from'vue-i18n';defineProps<{status:string}>();const{t}=useI18n()</script><style scoped>.badge{padding:3px 8px;border-radius:10px;background:#e2e8f0;font-size:12px}.badge[data-status=running]{background:#dbeafe;color:#1d4ed8}.badge[data-status=completed]{background:#dcfce7;color:#166534}.badge[data-status=failed],.badge[data-status=completed_with_errors]{background:#fee2e2;color:#991b1b}</style>
